(function(){
  var PAYWALL=['Subscribe to enjoy this recipe','Resubscribe to enjoy','Subscribe now','Cancel anytime','Delicious recipes for everyday','New recipe suggestions from our editors','Tips and tools to make cooking easier','access will expire','Update payment'];
  var SAFE=['Ingredient','INGREDIENT','Preparation','PREPARATION','Step 1','Step 2','Yield:','Total Time','Active Time'];
  function isSafe(el){
    var t=el.textContent||'';
    return SAFE.some(function(s){return t.includes(s);});
  }
  function countPaywallPhrases(t){
    return PAYWALL.reduce(function(n,p){return n+(t.includes(p)?1:0);},0);
  }
  function killSmallestPaywallContainer(){
    // Find leaf-most elements containing paywall phrases
    var candidates=[];
    document.querySelectorAll('div,section,aside').forEach(function(el){
      if(el.dataset.gremlinKilled) return;
      var txt=el.textContent||'';
      if(txt.length>1500) return;
      if(countPaywallPhrases(txt)>=2 && !isSafe(el)){
        candidates.push(el);
      }
    });
    // Keep only leaf-most (no candidate inside another candidate)
    candidates=candidates.filter(function(c){
      return !candidates.some(function(other){return other!==c && c.contains(other);});
    });
    // For each leaf, walk up MAX 3 levels and stop if parent gets unsafe or huge
    candidates.forEach(function(leaf){
      var target=leaf, depth=0;
      while(depth<3 && target.parentElement && target.parentElement!==document.body){
        var parent=target.parentElement;
        var ptxt=parent.textContent||'';
        if(ptxt.length>2500) break;
        if(isSafe(parent)) break;
        // Stop if parent has substantial non-paywall content
        var paywallLen=PAYWALL.reduce(function(n,p){var i=ptxt.indexOf(p);return i>=0?n+p.length:n;},0);
        if(ptxt.length-paywallLen>500) break;
        target=parent; depth++;
      }
      target.style.cssText='display:none!important';
      target.dataset.gremlinKilled='1';
    });
    // Restore scroll & blur
    document.body.style.overflow='';
    document.documentElement.style.overflow='';
    document.querySelectorAll('[style*="blur"]').forEach(function(el){
      if((el.style.filter||'').includes('blur')) el.style.filter='none';
    });
    document.querySelectorAll('[style*="mask"]').forEach(function(el){
      el.style.maskImage='none'; el.style.webkitMaskImage='none';
    });
  }
  killSmallestPaywallContainer();
  var obs=new MutationObserver(function(){killSmallestPaywallContainer();});
  obs.observe(document.body,{childList:true,subtree:true});
  setTimeout(function(){obs.disconnect();},20000);
})();
